  }
  .button {
    display: inline-block;
    background-color: #5cb85c; /* Green button */
    color: white;
    padding: 10px 20px;
    text-decoration: none;
    border-radius: 5px;
    margin-top: 15px;
  }
  .button:hover {
    background-color: #4cae4c;
  }
